INSERT INTO "public"."menu_items" ("id", "name", "description", "base_price", "category", "popular", "image_url", "created_at", "updated_at", "available", "sort_order", "variation_type") VALUES ('0077fd26-f8d3-4df3-9056-24d6d3b91cb6', 'SPICY GARLIC BUTTER WINGS', 'Crispy, golden-fried chicken wings tossed in our rich garlic butter sauce with a bold spicy kick. Each bite delivers the perfect balance of savory butter, aromatic garlic, and mouth-watering heat — irresistibly flavorful and satisfying.', '250.00', 'food', 'true', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1769939243363-3kjtor9lgv7.jpeg', '2026-02-01 09:47:27.380738+00', '2026-02-14 17:54:51.757017+00', 'true', '1', 'size'), ('008424b7-5311-444b-a46c-c6ad17e3022d', 'BLUE LEMON POP SODA', 'A refreshing fusion of bright lemon and subtle orange peel notes blended with sparkling soda. Light, citrusy, and beautifully uplifting in every sip.', '120.00', 'soda-splash', 'false', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1762257086980-gn6jchn7e3h.jpeg', '2025-11-04 11:53:52.41958+00', '2026-02-08 06:18:00.407509+00', 'true', '127', 'size'), ('042dcd49-275e-4c80-ba37-e86b804b33c5', 'SHIN RAMYUN SPICY', 'A classic Korean spicy noodle soup with a bold, flavorful broth and chewy noodles — perfect for those who love a satisfying, spicy kick.', '75.00', 'diy-korean-ramen', 'false', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1756733318427-uidexlixy3.webp', '2025-09-01 13:28:59.873934+00', '2026-01-08 13:06:47.625214+00', 'true', '104', 'size'), ('0496e80b-bc9b-47ec-89d5-d3ab1993c6c5', 'MATCHA TIRAMISU ', 'A Japanese twist on the classic Italian dessert — delicate layers of mascarpone cream and soft sponge infused with earthy matcha green tea. Lightly dusted with premium matcha powder for a perfectly ba', '130.00', 'cakes', 'true', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1756732384408-nfquyt7gj0g.jpg', '2025-08-30 06:44:53.565301+00', '2026-01-20 13:41:28.739576+00', 'false', '10', 'size'), ('04cc062d-e374-485a-8b30-8553ff32f7e1', 'GARDEN FRESH SANDWICH', '
A deliciously satisfying sandwich made with perfectly toasted wheat bread, filled with savory ham, crispy bacon, and perfectly scrambled eggs, layered with fresh tomato, cucumber, and crisp lettuce — a balanced blend of rich flavors and refreshing crunch in every bite.', '125.00', 'other-snacks', 'true', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1769731461860-4uuw7l7m5xs.jpeg', '2026-01-30 00:07:14.936445+00', '2026-02-16 06:03:16.292666+00', 'true', '5', 'size'), ('04fa9f20-da8e-4614-b152-aa082964f8cc', 'STEUARTS PREMIUM CEYLON BLACK TEA', 'This premium blend offers a smooth, malty flavor with subtle hints of citrus, leaving a clean and refreshing finish. Perfect for enjoying plain or with a touch of milk and honey, it delivers both energy and elegance in every cup.', '60.00', 'premium-hot-tea', 'false', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1759301896406-s8te719f65m.jpeg', '2025-10-01 07:00:24.255032+00', '2026-01-08 13:06:47.625214+00', 'true', '115', 'size'), ('0823e099-15ac-4077-be92-75d95e03a0f0', 'YEMA CHOCOLATE CAKE', 'Rich, creamy yema custard swirled with smooth chocolate, creating a perfect blend of sweet and indulgent flavors. A delightful treat for chocolate and caramel lovers alike!', '150.00', 'cakes', 'false', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1756732055983-h50nbsumnqk.jpg', '2025-08-30 06:43:49.536387+00', '2026-02-20 07:14:43.552751+00', 'true', '9', 'size'), ('0a29cfeb-acc4-4887-9fa1-fd98ee1cba77', '2 PC BONELESS CHICKEN TONKATSU', 'Crispy, golden boneless fried chicken served with steamed rice, fresh seasonal vegetables, and our house signature sauce for an extra burst of flavor. A deliciously satisfying meal made just for you!', '220.00', 'food', 'false', 'https://xnnracrkpapdfqcistvh.supabase.co/storage/v1/object/public/menu-images/1756728847680-76babv0ocyx.jpg', '2025-09-01 12:14:10.935702+00', '2026-02-16 07:07:17.859312+